#include <bits/stdc++.h>
using namespace std;

int main(){
	string a;
	cin>>a;
	int q=1,n=0;
	for(int i=0;i<12;i++){
		if(a[i]!='-'){ 
			int b=a[i]-48;
			n+=b*q;
			q++;
		}
	}
	if(n%11==(int(a[12]-48))||(n%11==10)&&a[12]=='X'){
		cout<<"Right";
	}else{
		for(int i=0;i<12;i++){
			cout<<a[i];
		}
		if(n%11==10){
			cout<<"X"; 
		}else{
			cout<<n%11;
		}
		
	}
	return 0;
}
